import{_ as i,W as o,X as p,Z as n,$ as a,a0 as s,a1 as t,D as l}from"./framework-c9619a7b.js";const c={},r=t('<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>mkcert可以在本地生成自签名证书，这些证书可以被本地信任，并且可以用于本地开发、测试和调试HTTPS应用程序，避免了使用公共CA证书的安全性和费用问题。</p><p>mkcert的主要特点包括：</p><ul><li><p><strong>本地信任</strong>：mkcert生成的证书可以被本地信任，避免了使用公共CA证书的安全性和费用问题。</p></li><li><p><strong>自签名证书</strong>：mkcert可以在本地生成自签名证书，可以用于本地开发、测试和调试HTTPS应用程序。</p></li><li><p><strong>多平台支持</strong>：mkcert可以运行在多种操作系统上，如Windows、macOS、Linux等，可以满足不同平台和环境的需求。</p></li><li><p><strong>简单易用</strong>：mkcert使用简单，只需要几个命令即可生成证书，并且可以与常见的Web服务器集成，如Apache、Nginx等。</p></li><li><p><strong>安全性</strong>：mkcert生成的证书采用了最新的加密算法和安全标准，保证了生成的证书的安全性和可靠性。</p></li><li><p><strong>免费开源</strong>：mkcert是一款开源的工具，可以免费使用和分发，没有任何使用限制和费用。</p></li></ul><p>总之，mkcert是一款功能强大的本地信任SSL/TLS证书生成工具，可以帮助用户生成本地信任的SSL/TLS证书，避免了使用公共CA证书的安全性和费用问题，具有简单易用、安全可靠、免费开源等特点，是现代Web开发中不可或缺的工具之一。</p>',5),d={href:"https://github.com/FiloSottile/mkcert",target:"_blank",rel:"noopener noreferrer"},u=n("h2",{id:"安装",tabindex:"-1"},[n("a",{class:"header-anchor",href:"#安装","aria-hidden":"true"},"#"),a(" 安装")],-1),g={href:"https://github.com/FiloSottile/mkcert/releases",target:"_blank",rel:"noopener noreferrer"},m=t(`<p>注： 该工具是个命令行工具，没有图形界面，需要在终端中使用。</p><h2 id="使用" tabindex="-1"><a class="header-anchor" href="#使用" aria-hidden="true">#</a> 使用</h2><h3 id="参数说明" tabindex="-1"><a class="header-anchor" href="#参数说明" aria-hidden="true">#</a> 参数说明</h3><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523184812.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="安装根证书" tabindex="-1"><a class="header-anchor" href="#安装根证书" aria-hidden="true">#</a> 安装根证书</h3><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token punctuation">.</span>\\mkcert-v1<span class="token punctuation">.</span>4<span class="token punctuation">.</span>4-windows-amd64<span class="token punctuation">.</span>exe <span class="token operator">-</span>install
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>命令执行后会出现弹窗：</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523185000.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>选择“是”，即可安装证书到系统。</p><p>验证：</p><p><code>Win+R</code>打开运行窗口，输入<code>certmgr.msc</code>回车打开证书管理器。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523185313.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>可以看到，根证书被安装到本地计算机的&quot;受信任的根证书颁发机构&quot;存储库中。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523185919.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="签发证书" tabindex="-1"><a class="header-anchor" href="#签发证书" aria-hidden="true">#</a> 签发证书</h3><p>mkcert支持生成下面类型的证书：</p>`,16),h={href:"http://example.com",target:"_blank",rel:"noopener noreferrer"},k=n("li",null,'"*.example.com"',-1),v=n("li",null,'"example.test"',-1),b=n("li",null,'"localhost"',-1),f=n("li",null,'"127.0.0.1"',-1),_=n("li",null,'"::1"',-1),x=t(`<p>以<code>app-local.kevin2li.top</code>为例，可以通过下面命令签发：</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token punctuation">.</span>\\mkcert-v1<span class="token punctuation">.</span>4<span class="token punctuation">.</span>4-windows-amd64<span class="token punctuation">.</span>exe app-local<span class="token punctuation">.</span>kevin2li<span class="token punctuation">.</span>top
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>可以看到，它会在当前目录下生成<code>pem</code>格式的证书文件和密钥文件。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523190155.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>此外，它还可以一次签发多个域名证书以及泛域名证书。</p><h3 id="分发根证书" tabindex="-1"><a class="header-anchor" href="#分发根证书" aria-hidden="true">#</a> 分发根证书</h3><p>为了让局域网内其他设备能够使用，我们需要将根证书分发到局域网其他机器上，可以通过下面命令查看根证书路径：</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token punctuation">.</span>\\mkcert-v1<span class="token punctuation">.</span>4<span class="token punctuation">.</span>4-windows-amd64<span class="token punctuation">.</span>exe <span class="token operator">-</span>CAROOT
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523190859.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>将<code>rootCA.pem</code>复制并重命名为<code>rootCA.crt</code>，这样windows设备直接双击就可以安装了。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523191431.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>在选择证书存储路径时，要选择“受信任的根证书颁发机构”</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523191757.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h3 id="使用自签证书" tabindex="-1"><a class="header-anchor" href="#使用自签证书" aria-hidden="true">#</a> 使用自签证书</h3><p>前面我们签发了一个<code>app-local.kevin2li.top</code>的证书，下面来使用它。</p><p>先准备一段python代码。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token comment"># ~/mkcert/main.py</span>
<span class="token keyword">import</span> http<span class="token punctuation">.</span>server
<span class="token keyword">import</span> ssl

<span class="token comment"># 配置服务器参数</span>
HOST <span class="token operator">=</span> <span class="token string">&#39;app-local.kevin2li.top&#39;</span>
PORT <span class="token operator">=</span> <span class="token number">443</span>
CERTFILE <span class="token operator">=</span> <span class="token string">&#39;./app-local.kevin2li.top.pem&#39;</span>  <span class="token comment"># SSL证书文件路径</span>
KEYFILE <span class="token operator">=</span> <span class="token string">&#39;./app-local.kevin2li.top-key.pem&#39;</span>   <span class="token comment"># SSL证书私钥文件路径</span>

<span class="token comment"># 创建HTTP服务器</span>
handler <span class="token operator">=</span> http<span class="token punctuation">.</span>server<span class="token punctuation">.</span>SimpleHTTPRequestHandler
httpd <span class="token operator">=</span> http<span class="token punctuation">.</span>server<span class="token punctuation">.</span>HTTPServer<span class="token punctuation">(</span><span class="token punctuation">(</span>HOST<span class="token punctuation">,</span> PORT<span class="token punctuation">)</span><span class="token punctuation">,</span> handler<span class="token punctuation">)</span>

<span class="token comment"># 添加SSL支持</span>
httpd<span class="token punctuation">.</span>socket <span class="token operator">=</span> ssl<span class="token punctuation">.</span>wrap_socket<span class="token punctuation">(</span>httpd<span class="token punctuation">.</span>socket<span class="token punctuation">,</span> certfile<span class="token operator">=</span>CERTFILE<span class="token punctuation">,</span> keyfile<span class="token operator">=</span>KEYFILE<span class="token punctuation">,</span> server_side<span class="token operator">=</span><span class="token boolean">True</span><span class="token punctuation">)</span>

<span class="token comment"># 启动服务器</span>
<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string-interpolation"><span class="token string">f&#39;Starting HTTPS server on https://</span><span class="token interpolation"><span class="token punctuation">{</span>HOST<span class="token punctuation">}</span></span><span class="token string">:</span><span class="token interpolation"><span class="token punctuation">{</span>PORT<span class="token punctuation">}</span></span><span class="token string">&#39;</span></span><span class="token punctuation">)</span>
httpd<span class="token punctuation">.</span>serve_forever<span class="token punctuation">(</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>运行<code>python main.py</code></p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523200655.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p><strong>域名解析：</strong></p><p>由于是在内网环境下，没有公共DNS解析，也没有设置内网DNS解析服务器，简单起见，我们通过修改<code>hosts</code>文件来将域名映射到ip。</p><p><code>hosts</code>文件路径：</p><ul><li>Windows系统：C:\\Windows\\System32\\drivers\\etc\\hosts</li><li>macOS系统：/private/etc/hosts</li><li>Linux系统：/etc/hosts</li></ul><p>在<code>hosts</code>文件最后添加下面内容，将域名映射到本机地址或内网地址(二选一)：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 127.0.0.1 app-local.kevin2li.top</span>
<span class="token number">192.168</span>.1.104 app-local.kevin2li.top
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>本机浏览器访问：</strong></p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523200615.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>可以看到实现了内网的https访问。</p><p>点击浏览器的地址栏旁边的小锁图标，在“连接安全”里可以看到具体的证书信息。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523202425.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p><strong>局域网其他设备访问：</strong></p><p>通过导入根证书，并修改<code>hosts</code>文件将域名指向内网服务器ip，也可以达到一样的效果。</p><figure><img src="https://minio.kevin2li.top/image-bed/blog/20230523203359.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><h2 id="参考" tabindex="-1"><a class="header-anchor" href="#参考" aria-hidden="true">#</a> 参考</h2>`,34),S={href:"https://www.loowp.com/24938.html",target:"_blank",rel:"noopener noreferrer"};function w(y,T){const e=l("ExternalLinkIcon");return o(),p("div",null,[r,n("p",null,[a("Github: "),n("a",d,[a("https://github.com/FiloSottile/mkcert"),s(e)])]),u,n("p",null,[a("下载二进制： "),n("a",g,[a("https://github.com/FiloSottile/mkcert/releases"),s(e)])]),m,n("ul",null,[n("li",null,[a('"'),n("a",h,[a("example.com"),s(e)]),a('"')]),k,v,b,f,_]),x,n("ol",null,[n("li",null,[n("a",S,[a("云创源码 | 利用mkcert快速一键自签名局域网SSL证书本地 https 实现"),s(e)])])])])}const z=i(c,[["render",w],["__file","使用mkcert签发本地自签名证书教程.html.vue"]]);export{z as default};
